from beeai import AgentMemory
import json
import re

def pii_safe_serialize(state):
    def scrub_pii(obj):
        if isinstance(obj, str):
            # Remove common PII patterns
            obj = re.sub(r'\b\d{3}-\d{3}-\d{4}\b', '[REDACTED_SSN]', obj)
            obj = re.sub(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b', '[REDACTED_EMAIL]', obj)
            return obj
        elif isinstance(obj, dict):
            return {k: scrub_pii(v) for k, v in obj.items()}
        elif isinstance(obj, list):
            return [scrub_pii(item) for item in obj]
        return obj

    return json.dumps(scrub_pii(state))

