from beeai.tools import ToolWrapper
import re

PII_REPLACEMENTS = {
    r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b': '[EMAIL]',
    r'\b\d{3}-\d{3}-\d{4}\b': '[SSN]',
    r'\b\d{3}[\s-]?\d{2}[\s-]?\d{4}\b': '[PHONE]',
    r'\b\d{16}\b': '[CARD]'
}

class PIIToolWrapper(ToolWrapper):
    def sanitize_params(self, params):
        params_str = str(params)
        for pattern, replacement in PII_REPLACEMENTS.items():
            params_str = re.sub(pattern, replacement, params_str)
        return params_str

    def execute(self, tool_name, params):
        safe_params = self.sanitize_params(params)
        return super().execute(tool_name, safe_params)

agent = Agent()
agent.tool_wrapper = PIIToolWrapper()
